<?phpnamespace app\dep\Blog;use app\enum\BlogEnum;use app\enum\CommonEnum;use app\model\Blog\BlogModel;class BlogDep{    public $model;    public function __construct()    {        $this->model = new BlogModel();    }    public function first($id)    {        $res = $this->model->where('id', $id)->first();        return $res;    }    public function carousel()    {        $res = $this->model->where("status",BlogEnum::RELEASE)->where('is_carousel', CommonEnum::YES)->where('is_del', CommonEnum::NO)->get();        return $res;    }    public function firstBySuperAdmin()    {        $res = $this->model->where('name', '超级管理员')->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function firstByAdmin()    {        $res = $this->model->where('name', '管理员')->where('is_del', CommonEnum::NO)->first();        return $res;    }     public function firstByTitle($name)    {        $res = $this->model->where('title', $name)->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function getUserByToken($token)    {        $res = $this->model->where('token', $token)->first();        return $res;    }    public function firstByEmail($email){        $res = $this->model->where('email',$email)->first();        return $res;    }    public function firstByToken($token){        $res = $this->model->where('token',$token)->first();        return $res;    }    public function all()    {        $res = $this->model->all();        return $res;    }    public function allOK()    {        $res = $this->model->where('is_del', CommonEnum::NO)->get();        return $res;    }    public function releaseAll($userId)    {        $res = $this->model->where('created_user_id', $userId)->where('is_del', CommonEnum::NO)->where('status', BlogEnum::RELEASE)->get();        return $res;    }    public function add($data)    {        $res = $this->model->insertGetId($data);        return $res;    }    public function edit($id, $data)    {        if(!is_array($id)){            $id = [$id];        }        $res = $this->model->whereIn('id', $id)->update($data);        return $res;    }    public function batchEdit($ids, $data)    {        $res = $this->model->whereIn('id', $ids)->update($data);        return $res;    }    public function del($id, $data)    {        if(!is_array($id)){            $id = [$id];        }        $res = $this->model->whereIn('id', $id)->update($data);        return $res;    }    public function list($param){        $res = $this->model            ->where('is_del', CommonEnum::NO)            ->where('status', BlogEnum::RELEASE)            ->when(!empty($param['title']), function ($query) use ($param) {                $query->where('title','like' ,"%{$param['title']}%");            })            ->when(!empty($param['type']), function ($query) use ($param) {                $query->where('type',$param['type']);            })            ->when(!empty($param['category_id']), function ($query) use ($param) {                $query->where('category_id',$param['category_id']);            })            ->when(!empty($param['status']), function ($query) use ($param) {                $query->where('status',$param['status']);            })            ->when(!empty($param['tag_id']), function ($query) use ($param) {                $tagIds = $param['tag_id'];                // 使用 JSON 查询筛选                $query->where(function ($query) use ($tagIds) {                    foreach ($tagIds as $tagId) {                        $query->orWhereRaw("JSON_CONTAINS(tag_id, ?)", [json_encode($tagId)]);                    }                });            })            ->orderBy('is_top','asc')            ->paginate($param['page_size'], ['*'], 'page', $param['current_page']);        return $res;    }}